# Check if gVisor runtime is available, then run with it if possible.
import subprocess, json, warnings

def run_with_best_runtime(command: list[str], image: str) -> dict:
    result = subprocess.run(
        ["docker", "info", "--format", "{{json .Runtimes}}"],
        capture_output=True, text=True, check=True,
    )
    runtimes = json.loads(result.stdout)
    runtime = "runsc" if "runsc" in runtimes else "runc"
    if runtime == "runc":
        warnings.warn("gVisor not available; falling back to runc.")

    proc = subprocess.run(
        ["docker", "run", "--rm", "--runtime", runtime,
         "--network", "none", "--memory", "128m",
         "--read-only", "--tmpfs", "/tmp:size=32m",
         "--no-new-privileges", "--cap-drop", "ALL",
         "--user", "65534:65534", image] + command,
        capture_output=True, text=True, timeout=30,
    )
    return {"returncode": proc.returncode, "stdout": proc.stdout, "runtime": runtime}

# Scan image for CVEs using Trivy
def scan_image(image: str) -> list[dict]:
    result = subprocess.run(
        ["trivy", "image", "--format", "json", "--quiet", image],
        capture_output=True, text=True,
    )
    if result.returncode != 0:
        return []
    data = json.loads(result.stdout)
    return [
        {"id": v["VulnerabilityID"], "severity": v["Severity"], "pkg": v["PkgName"]}
        for r in data.get("Results", [])
        for v in r.get("Vulnerabilities", [])
    ]
